import{_ as e,o as a,c as s,a2 as d}from"./chunks/framework.D14Z5eOz.js";const g=JSON.parse('{"title":"Available AI agents","description":"","frontmatter":{},"headers":[],"relativePath":"reference/agents.md","filePath":"reference/agents.md","lastUpdated":1784865624000}'),o={name:"reference/agents.md"};function i(l,t,n,r,c,h){return a(),s("div",null,[...t[0]||(t[0]=[d(`<h1 id="available-ai-agents" tabindex="-1">Available AI agents <a class="header-anchor" href="#available-ai-agents" aria-label="Permalink to &quot;Available AI agents&quot;">​</a></h1><p>At <strong><code>sdd init</code></strong> you install <strong>exactly one</strong> AI coding agent host. Switch later with <code>sdd agents install --ai &lt;host&gt; --force</code>.</p><h2 id="hosts" tabindex="-1">Hosts <a class="header-anchor" href="#hosts" aria-label="Permalink to &quot;Hosts&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Init flag</th><th>Product</th><th>What gets installed</th><th>How you use it</th></tr></thead><tbody><tr><td><code>--ai copilot</code></td><td><strong>GitHub Copilot</strong></td><td><code>.github/agents/*.agent.md</code>, <code>AGENTS.md</code>, <code>.sdd/protocol.md</code></td><td>Copilot Chat → agent <code>sdd</code></td></tr><tr><td><code>--ai grok</code></td><td><strong>Grok Build</strong></td><td><code>.grok/rules/sdd.md</code>, <code>AGENTS.md</code>, <code>.sdd/protocol.md</code></td><td><code>grok</code> CLI / Grok Build</td></tr><tr><td><code>--ai claude</code></td><td><strong>Claude Code</strong></td><td><code>.claude/agents/*.md</code>, <code>AGENTS.md</code>, <code>.sdd/protocol.md</code></td><td><code>claude</code> CLI</td></tr><tr><td><code>--ai ollama</code></td><td><strong>Ollama (local)</strong></td><td><code>.ollama/sdd.md</code>, <code>AGENTS.md</code>, <code>.sdd/protocol.md</code></td><td><code>ollama run &lt;model&gt;</code> (local LLM)</td></tr></tbody></table><p>Interactive init (no <code>--ai</code>) prompts you to pick one of these.</p><h2 id="ollama-setup" tabindex="-1">Ollama setup <a class="header-anchor" href="#ollama-setup" aria-label="Permalink to &quot;Ollama setup&quot;">​</a></h2><ol><li>Install <a href="https://ollama.com" target="_blank" rel="noreferrer">Ollama</a> and ensure <code>ollama</code> is on <code>PATH</code>.</li><li>Pull a model, e.g. <code>ollama pull llama3.2</code> (or any chat model you prefer).</li><li>Init SDD with Ollama:</li></ol><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sdd</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> init</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --here</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --ai</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ollama</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># optional: export SDD_OLLAMA_MODEL=qwen2.5-coder   # default: llama3.2</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sdd</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> new</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;Fix empty list crash&quot;</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -w</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> hotfix</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -y</span></span></code></pre></div><p>When <code>sdd</code> launches the agent it runs roughly:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">ollama</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> run</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">$SDD_OLLAMA_MODEL</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;&lt;kickoff from handoff&gt;&quot;</span></span></code></pre></div><p>Ollama does <strong>not</strong> auto-load multi-role agent trees like Claude. Project guidance lives in:</p><ul><li><code>.ollama/sdd.md</code> — thin SDD router brief</li><li><code>AGENTS.md</code> — host pointer</li><li><code>.sdd/handoff.md</code> + <code>.sdd/active-context.md</code> — live task</li></ul><p>Set the model with <strong><code>SDD_OLLAMA_MODEL</code></strong> or <strong><code>OLLAMA_MODEL</code></strong> (default <code>llama3.2</code>).</p><h2 id="agent-roles-stubs" tabindex="-1">Agent roles (stubs) <a class="header-anchor" href="#agent-roles-stubs" aria-label="Permalink to &quot;Agent roles (stubs)&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Role id</th><th>Purpose</th><th>Copilot / Claude</th><th>Grok / Ollama</th></tr></thead><tbody><tr><td><code>sdd</code></td><td>Router from current stage</td><td>Yes</td><td>Single brief file</td></tr><tr><td><code>sdd-planner</code></td><td>Specs only</td><td>Yes</td><td>Use router + stage</td></tr><tr><td><code>sdd-implementer</code></td><td>Code for active change</td><td>Yes</td><td>Use router + stage</td></tr><tr><td><code>sdd-reviewer</code></td><td>Check acceptance</td><td>Yes</td><td>Use router + stage</td></tr></tbody></table><p>Real process rules: <strong><code>.sdd/protocol.md</code></strong>. Live task: <strong><code>.sdd/active-context.md</code></strong> / <strong><code>.sdd/handoff.md</code></strong>.</p><h2 id="process-commands-vs-agent-launch" tabindex="-1">Process commands vs agent launch <a class="header-anchor" href="#process-commands-vs-agent-launch" aria-label="Permalink to &quot;Process commands vs agent launch&quot;">​</a></h2><p>Most process commands refresh handoff and <strong>launch</strong> the configured agent.<br><strong>Do not launch:</strong> <code>status</code>, <code>init</code>, <code>workflows</code>, <code>context</code>, <code>doctor</code>.</p><p>Skip launch once: <code>--no-agent</code> or <code>SDD_NO_AGENT=1</code>.</p><h2 id="switch-host-later" tabindex="-1">Switch host later <a class="header-anchor" href="#switch-host-later" aria-label="Permalink to &quot;Switch host later&quot;">​</a></h2><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sdd</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> agents</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> install</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --ai</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ollama</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --force</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sdd</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> agents</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> refresh</span></span></code></pre></div><h2 id="related" tabindex="-1">Related <a class="header-anchor" href="#related" aria-label="Permalink to &quot;Related&quot;">​</a></h2><ul><li><a href="./../guides/simple-feature">Simple feature</a></li><li><a href="./cli">CLI reference</a></li></ul>`,23)])])}const k=e(o,[["render",i]]);export{g as __pageData,k as default};
